         _nvp = rtxUTF8StrJoin (pctxt, _name, (OSUTF8CHAR *)":", _value, 0, 0);

         pvalue->u.extElem1->data = (OSOCTET *)_nvp;
         pvalue->u.extElem1->numocts = rtxUTF8Len (_nvp) + 1;
