      if (0 == rtxUTF8Strcmp (_choiceId, (OSUTF8CHAR *)"valueOctS"))
      {
         pvalue->u.valueOctS = rtxMemAllocType (pctxt, ASN1TDynOctStr);
         pvalue->u.valueOctS->numocts = 0;
         pvalue->u.valueOctS->data = 0;
         stat = rtJsonDecDynHexStr (pctxt, pvalue->u.valueOctS);
         if (stat != 0) return LOG_RTERR (pctxt, stat);
         if (stat != 0) return LOG_RTERR (pctxt, stat);

         pvalue->t = 5;

         break;
      }
