         case 2:
            RTXCTXTPUSHELEMNAME (pctxt, "noValue");

            Asn1NamedEventHandler::invokeStartElement (pctxt, "noValue", -1);
            /* NULL */

            Asn1NamedEventHandler::invokeNullValue (pctxt);
            Asn1NamedEventHandler::invokeEndElement (pctxt, "noValue", -1);

            RTXCTXTPOPELEMNAME (pctxt);

            break;

